import{_ as a,o as e,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"昆明湖与十七孔桥","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/kunming-lake.md","filePath":"landmarks/summer-palace/kunming-lake.md","lastUpdated":1784720050000}'),r={name:"landmarks/summer-palace/kunming-lake.md"};function n(i,t,s,d,u,g){return e(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="昆明湖与十七孔桥" tabindex="-1">昆明湖与十七孔桥 <a class="header-anchor" href="#昆明湖与十七孔桥" aria-label="Permalink to &quot;昆明湖与十七孔桥&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1768036599772-0810f884ebb5?w=1200&amp;q=80" alt="昆明湖十七孔桥"></p><blockquote><p>&quot;何处燕山最畅情，无双风月属昆明。&quot; —— 一片湖水，三座仙山，十七孔夕阳</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>昆明湖是颐和园的灵魂，水面达220公顷，约占全园面积的四分之三。它以杭州西湖为蓝本开凿而成，西堤六桥仿西湖苏堤，三座岛屿应&quot;海上三仙山&quot;之典，远借玉泉山塔与西山群峰，近映<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>金顶，是中国皇家园林中&quot;移天缩地&quot;手法的极致体现。</p><p>泛舟湖上，春看西堤桃柳、夏赏满湖风荷、秋望芦荻残阳、冬候金光穿洞，四时之景不同，而乐亦无穷。</p><p>湖的前身是元明以来的天然湖泊&quot;瓮山泊&quot;。乾隆十五年（1750年）修建清漪园时，乾隆帝仿汉武帝在长安开凿昆明池操练水师的典故，将湖面疏浚扩展，挖出的土方堆筑成万寿山，并正式赐名&quot;昆明湖&quot;。湖中有南湖岛、藻鉴堂、治镜阁三座岛屿，象征蓬莱、方丈、瀛洲三座海上仙山——这是自秦汉以来皇家园林&quot;一池三山&quot;格局的延续。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">元明时期</td><td style="text-align:left;">天然湖泊&quot;瓮山泊&quot;，为京师西郊水源</td></tr><tr><td style="text-align:left;">清乾隆十五年（1750）</td><td style="text-align:left;">疏浚扩展，堆土成山，赐名&quot;昆明湖&quot;，效汉武帝昆明池练水师之典</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">沿岸建筑遭英法联军焚毁，湖面与桥体幸存</td></tr><tr><td style="text-align:left;">光绪年间</td><td style="text-align:left;">慈禧重建沿岸殿宇，昆明湖恢复旧观</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">冬季开辟冰场，冬至&quot;金光穿洞&quot;成为现象级景观</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>湖面面积</strong></td><td style="text-align:left;">220公顷，占全园约四分之三</td></tr><tr><td style="text-align:left;"><strong>三岛</strong></td><td style="text-align:left;">南湖岛、藻鉴堂、治镜阁（象征蓬莱、方丈、瀛洲）</td></tr><tr><td style="text-align:left;"><strong>十七孔桥</strong></td><td style="text-align:left;">长150米，宽8米，17个桥孔，544只石狮</td></tr><tr><td style="text-align:left;"><strong>东堤胜迹</strong></td><td style="text-align:left;">铜牛、廓如亭（八方亭）、文昌阁</td></tr><tr><td style="text-align:left;"><strong>南湖岛</strong></td><td style="text-align:left;">涵虚堂（仿武昌黄鹤楼）、龙王庙、月波楼</td></tr><tr><td style="text-align:left;"><strong>西堤</strong></td><td style="text-align:left;">六桥桃柳，详见<a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤六桥</a></td></tr></tbody></table><p>十七孔桥是园内最大的石桥，长150米、宽8米，17个桥孔由中央向两端渐次收小，如长虹饮涧。桥上544只石狮形态各异，比卢沟桥的石狮还多。</p><p>桥头东端的廓如亭（俗称八方亭）重檐攒尖，是颐和园最大的亭子；亭旁铜牛卧于东堤，牛背铸乾隆御制《金牛铭》，取&quot;大禹铸铁牛镇水&quot;之意，保佑昆明湖永不泛滥。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="冬至-金光穿洞" tabindex="-1">冬至&quot;金光穿洞&quot; <a class="header-anchor" href="#冬至-金光穿洞" aria-label="Permalink to &quot;冬至&quot;金光穿洞&quot;&quot;">​</a></h3><p>每年冬至前后的傍晚，太阳落到西南方恰好与十七孔桥成一条直线，落日余晖自西南斜射而来，将十七个桥洞逐一照亮，金光灿灿如十七盏明灯，史称&quot;金光穿洞&quot;。这一奇观只在冬至前后约半个月内出现，每次持续二十分钟左右。</p><p>近几年&quot;金光穿洞&quot;走红网络，冬至的昆明湖东堤往往聚集上千名摄影爱好者，三脚架一字排开，只为那一束穿越百年的金光。这是造园家与天文学家共同写下的&quot;彩蛋&quot;——桥的朝向，早在1750年就已算准。</p><h3 id="铜牛与织女" tabindex="-1">铜牛与织女 <a class="header-anchor" href="#铜牛与织女" aria-label="Permalink to &quot;铜牛与织女&quot;">​</a></h3><p>昆明湖东堤有铜牛，西堤西侧原有&quot;耕织图&quot;景区，一牛一织，隔湖相望，暗合牛郎织女的典故；乾隆还在湖畔立&quot;织女图&quot;石碑，以昆明湖作银河。更妙的是，乾隆将这片湖命名为&quot;昆明&quot;，既效仿汉武帝操练水师，又以水军演练呼应&quot;天河&quot;意象——帝王的浪漫，从来都带着经世致用的注脚。</p><p>铜牛历经1860年大火和1900年八国联军劫掠（牛尾曾被锯断盗卖），依然卧守东堤，是昆明湖沧桑最沉默的见证者。</p><h3 id="一池三山的千年执念" tabindex="-1">一池三山的千年执念 <a class="header-anchor" href="#一池三山的千年执念" aria-label="Permalink to &quot;一池三山的千年执念&quot;">​</a></h3><p>&quot;一池三山&quot;是中国皇家园林延续两千年的造园母题：秦始皇遣徐福求仙不得，汉武帝在长安建章宫挖太液池、堆三岛，以人间山水模拟蓬莱、方丈、瀛洲，把求而不得的仙境搬进了皇家禁苑。此后历代宫苑皆循此制。乾隆扩建昆明湖时布下南湖岛、藻鉴堂、治镜阁三岛，正是这一传统的收官之作——从秦汉帝王的求仙幻梦，到清代的园林美学，三座小岛串起半部中国造园史。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>十七孔桥与金光穿洞</strong>：桥上数石狮、桥下看倒影，冬至傍晚来等一场金光穿洞，胜过千言万语。</li><li><strong>南湖岛涵虚堂</strong>：登堂北望，佛香阁、排云殿、万寿山层层叠起，是拍摄颐和园标准照的最佳机位。</li><li><strong>铜牛与金牛铭</strong>：细读牛背上的乾隆铭文，再听听&quot;金牛镇水&quot;的民间传说。</li><li><strong>三岛仙踪</strong>：乘船登上南湖岛，远观藻鉴堂、治镜阁遗址，体会&quot;一池三山&quot;的造园密码。</li><li><strong>画舫凌波</strong>：从石舫码头乘大船横渡昆明湖，湖上回望万寿山，视角与岸上截然不同。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>东堤铜牛处</strong>：以铜牛为前景拍十七孔桥全景，黄昏时分桥影横陈最美。</li><li><strong>南湖岛北望</strong>：颐和园官方明信片的机位，万寿山佛香阁与水面倒影同框。</li><li><strong>船上回望</strong>：游船至湖心回望万寿山，长焦压缩空间，殿宇如山间天宫。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>昆明湖环湖一圈约15公里，全程徒步需大半天；建议结合游船（大船40元、小船60-80元/小时），石舫至南湖岛航线最经典。</li><li>拍十七孔桥全景去东堤铜牛附近；拍佛香阁倒影去南湖岛或西堤——&quot;横看成岭侧成峰&quot;。</li><li>冬至&quot;金光穿洞&quot;约在12月20日前后的16:00-16:20出现，需提前占位、注意保暖。</li><li>夏季赏荷集中在西堤与南湖岛间水域，7-8月最盛；冬季湖面结冰开放冰场，又是另一番热闹。</li><li>西堤沿线串联<a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤六桥</a>，步行约1小时，桃花季的西堤是整座园林的颜值巅峰。</li><li>湖边风大，春秋两季记得带件外套；带面包屑喂鱼喂鸥是孩子们的最爱（请在指定区域投喂）。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：昆明湖可以游泳吗？</strong></p><p>不可以，全湖禁止游泳。夏季可以划船（大船40元，小船按小时计费），冬季冰层达标后开放冰场滑冰。</p><p><strong>Q：十七孔桥的石狮真的比卢沟桥多吗？</strong></p><p>是的。十七孔桥有石狮544只，卢沟桥约501只（历代修补，计数说法略有出入），民间&quot;数不清&quot;的传说两桥都有份。</p><p><strong>Q：金光穿洞什么时候去最好？</strong></p><p>冬至前后约半个月（12月15日-12月底），日落前20分钟左右（约16:00-16:20）；越早去占位越好，注意保暖。</p><p><strong>Q：冬天昆明湖有什么好玩的？</strong></p><p>三样：金光穿洞（冬至前后）、雪后湖山（&quot;西山晴雪&quot;意境）、冰场滑冰（通常1月开放，视冰层厚度而定）。</p><hr><p><strong>📍 位置</strong>：颐和园南部与西部水域，十七孔桥连接东堤与南湖岛 <strong>⏱️ 建议游览</strong>：1-2小时（不含游船） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',39)])])}const p=a(r,[["render",n]]);export{q as __pageData,p as default};
